import {
  AnnotationsMarkerConfig,
  NumericalMarkerProps,
  TimeMarkerProps,
} from '../types/annotations-marker-props.js';

/**
 * Identify whether a marker has numerical data
 * @param marker -
 */
export const isNumericalMarker = (
  marker: TimeMarkerProps | NumericalMarkerProps,
): marker is NumericalMarkerProps => {
  return typeof marker.start === 'number';
};

/**
 * Identify whether data contains numerical values
 * @param markers -
 */
export const isNumericalData = (markers: AnnotationsMarkerConfig[]) =>
  isNumericalMarker(markers[0]);
